// --------------------------------------------------
// DEBOUNCE CHECK v15 - Atomic latest-message validation
// After debounce wait, continue only if this message is still latest
// --------------------------------------------------

const mergedData = $('Merge Input').first().json;
const saveNode = $('Save Incoming Message').first();

let ourId = null;
const savedBody = saveNode.json;

if (Array.isArray(savedBody)) {
  if (savedBody.length > 0 && savedBody[0]?.id !== undefined) {
    ourId = savedBody[0].id;
  }
} else if (savedBody && typeof savedBody === 'object') {
  if (savedBody.id !== undefined) {
    ourId = savedBody.id;
  }
}

if (ourId === null || ourId === undefined) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'could_not_extract_saved_message_id' } }];
}

const rpcResult = $('Check Is Latest (RPC)').first().json;

let isLatest = false;
if (typeof rpcResult === 'boolean') {
  isLatest = rpcResult;
} else if (Array.isArray(rpcResult) && rpcResult.length > 0) {
  isLatest = rpcResult[0] === true || rpcResult[0]?.check_is_latest_message === true;
} else if (rpcResult && typeof rpcResult === 'object') {
  isLatest = rpcResult.check_is_latest_message === true || rpcResult.result === true;
}

if (!isLatest) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'not_latest' } }];
}

return [{ json: { ...mergedData, should_continue: true, our_id: ourId } }];

// --------------------------------------------------
// MERGE & AGGREGATE recent user messages v15
// Consolidates burst messages from the last 40 seconds into one reply
// --------------------------------------------------

const mergedData = $('Debounce Check v14').first().json;

let recentRaw = [];
try {
  recentRaw = $('Fetch Recent Messages').all();
} catch (e) {
  recentRaw = [];
}

const byId = new Map();
for (const item of recentRaw) {
  const payload = item.json;
  const rows = Array.isArray(payload) ? payload : [payload];
  for (const row of rows) {
    if (!row || row.id === undefined || row.id === null) continue;
    byId.set(row.id, row);
  }
}

const recentMessages = [...byId.values()]
  .filter((row) => row.role === 'user')
  .sort((a, b) => new Date(a.created_at) - new Date(b.created_at));

if (recentMessages.length <= 1) {
  return [{ json: { ...mergedData, messages_merged: 1 } }];
}

const combined = recentMessages
  .map((m) => String(m.message || '').trim())
  .filter((m) => m && m !== '(vacío)')
  .join(' ');

return [{
  json: {
    ...mergedData,
    user_message: combined || mergedData.user_message,
    messages_merged: recentMessages.length
  }
}];

// =============================================
// BUILD AI CONTEXT v18 - structured context for subagents
// =============================================

if ($input.context.itemIndex > 0) return [];

const merged = $('Merge & Aggregate Messages').first().json;

// --- Customer Profile ---
let customerData = {};
try {
  const raw = $('Fetch Customer Profile').first().json;
  if (Array.isArray(raw) && raw.length > 0) customerData = raw[0];
  else if (raw && raw.manychat_id) customerData = raw;
} catch (e) {
  customerData = {};
}

// --- Conversation History ---
let historyRows = [];
try {
  const items = $('Fetch Conversation History').all();
  for (const item of items) {
    const d = item.json;
    if (Array.isArray(d)) historyRows.push(...d);
    else if (d && d.role && d.message) historyRows.push(d);
  }
} catch (e) {
  historyRows = [];
}

// --- Product Catalog + IMAGE/STOCK MAPS ---
let productRows = [];
let productImages = {};
let productKeyNameMap = {};
let productStockMap = {};

const normalizeBrand = (value) => {
  const v = String(value || '').toLowerCase();
  if (v.includes('iphone') || v.includes('apple')) return 'IPHONE';
  if (v.includes('samsung')) return 'SAMSUNG';
  if (v.includes('redmi') || v.includes('poco') || v.includes('xiaomi')) return 'REDMI/POCO';
  return 'OTHER';
};

try {
  const items = $('Fetch Products').all();
  for (const item of items) {
    let d = item.json;
    if (d && d.data && Array.isArray(d.data)) d = d.data;

    const rows = Array.isArray(d) ? d : (d ? [d] : []);
    for (const p of rows) {
      if (!p || !p.product_key) continue;

      const brand = normalizeBrand(p.category);
      const imageUrl = p.image_url || p.image || p.url || '';

      const row = {
        id: p.id,
        product_key: String(p.product_key),
        brand,
        category: p.category || null,
        product_name: p.product_name || String(p.product_key),
        ram_gb: p.ram_gb ?? null,
        storage_gb: p.storage_gb ?? null,
        color: p.color ?? null,
        network: p.network ?? null,
        price_ars: p.price_ars ?? null,
        promo_price_ars: p.promo_price_ars ?? null,
        price_usd: p.price_usd ?? null,
        bancarizada_total: p.bancarizada_total ?? null,
        bancarizada_cuota: p.bancarizada_cuota ?? null,
        macro_total: p.macro_total ?? null,
        macro_cuota: p.macro_cuota ?? null,
        cuotas_qty: p.cuotas_qty ?? 6,
        in_stock: p.in_stock !== false,
        delivery_type: p.delivery_type ?? 'immediate',
        delivery_days: p.delivery_days ?? 0,
        image_url: String(imageUrl || '').trim()
      };

      productRows.push(row);
      productKeyNameMap[row.product_key] = String(row.product_name || '').trim();
      productStockMap[row.product_key] = row.in_stock;

      if (row.image_url && row.image_url.startsWith('http')) {
        productImages[row.product_key] = row.image_url;
      }
    }
  }
} catch (e) {
  productRows = [];
}

const incomingHumanActive = merged.is_human_active === true;
const customerHumanAssigned = customerData.human_assigned === true;
const humanAssigned = incomingHumanActive || customerHumanAssigned;

if (humanAssigned) {
  return [{
    json: {
      skip_ai: true,
      reason: incomingHumanActive ? 'manychat_human_active' : 'customer_human_assigned',
      subscriber_id: merged.subscriber_id,
      first_name: merged.first_name,
      phone: merged.phone,
      user_message: merged.user_message,
      was_audio: merged.was_audio,
      customer_id: customerData.id || null,
      customer_profile: customerData,
      product_catalog: productRows,
      product_images: productImages,
      product_key_name_map: productKeyNameMap,
      product_stock_map: productStockMap
    }
  }];
}

historyRows.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));

const userHistoryCount = historyRows.filter((h) => h.role === 'user').length;
const totalInteractions = Number(customerData.total_interactions || 0);
const isFirstInteraction = totalInteractions <= 1 || userHistoryCount <= 1;

const historyCompact = historyRows.slice(-20).map((h) => ({
  role: h.role,
  message: h.message,
  created_at: h.created_at
}));

const storePolicies = {
  payments: 'Transferencia bancaria en pesos, transferencia en dólares, Bitcoin y USDT (TRC-20) 0% recargo, efectivo en pesos/dólares solo Salta Capital. No créditos personales.',
  shipping: 'Envíos GRATIS a sucursal (BusPack/Flecha Carga, OCA, Vía Cargo). Sin costo de despacho ni embalaje. Despacho desde 72 horas hábiles. Salta Capital entrega en el día. Interior de Salta 24 hs.',
  location: 'Caseros 1365, Salta Capital. Diagonal a OCA.',
  human_hours: 'Lun-Vie 10:00-13:00 y 18:00-21:00 | Sáb 10:00-13:00 | Dom cerrado'
};

return [{
  json: {
    skip_ai: false,
    subscriber_id: merged.subscriber_id,
    first_name: merged.first_name,
    phone: merged.phone,
    user_message: merged.user_message || '',
    was_audio: merged.was_audio,
    customer_id: customerData.id || null,
    customer_profile: customerData,
    history_compact: historyCompact,
    is_first_interaction: isFirstInteraction,
    product_catalog: productRows,
    product_images: productImages,
    product_key_name_map: productKeyNameMap,
    product_stock_map: productStockMap,
    store_policies: storePolicies
  }
}];

// Process response from subagent contracts + hard delivery guards (ManyChat limits)

const data = $input.first().json;
const mergedData = $('Merge & Aggregate Messages').first().json;
const contextData = $('Build AI Context').first().json;

const orchestrator = data.agent_orchestrator || {};
const catalog = data.agent_catalog || {};
const media = data.agent_media || {};
const delivery = data.agent_delivery || {};

const escapeRegExp = (value) => String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const productKeyNameMap = contextData.product_key_name_map || {};

const keyAliasPairs = Object.entries(productKeyNameMap).flatMap(([key, name]) => {
  const human = String(name || key).trim();
  const variants = [key, key.replace(/_/g, '-'), key.replace(/-/g, '_')];
  return [...new Set(variants)].map((variant) => ({ alias: variant, human }));
});

const sanitizeInternalIds = (text) => {
  let out = String(text || '');

  out = out
    .replace(/\bError:\s*/gi, '')
    .replace(/product[_\s-]?keys?/gi, 'modelos')
    .replace(/c[oó]digos?\s+internos?/gi, 'modelos')
    .replace(/`([^`]+)`/g, '$1');

  for (const pair of keyAliasPairs) {
    const re = new RegExp(`\\b${escapeRegExp(pair.alias)}\\b`, 'gi');
    out = out.replace(re, pair.human);
  }

  out = out.replace(/\b[a-z0-9]+(?:[-_][a-z0-9]+){3,}\b/gi, 'ese modelo');
  return out.replace(/\s{2,}/g, ' ').trim();
};

const mapIntent = (intentRaw) => {
  const intent = String(intentRaw || '').trim().toLowerCase();
  const allowed = new Set(['greeting', 'price_inquiry', 'stock_check', 'comparison', 'purchase_intent', 'cuotas_inquiry', 'shipping_inquiry', 'complaint', 'off_topic', 'followup', 'ambiguous']);
  if (allowed.has(intent)) return intent;
  if (intent === 'shipping') return 'shipping_inquiry';
  if (intent === 'catalog') return 'price_inquiry';
  return 'followup';
};

const mapFunnel = (intent, needsHuman) => {
  if (needsHuman) return 'human_handoff';
  if (intent === 'greeting') return 'new';
  if (intent === 'purchase_intent') return 'closing';
  if (['price_inquiry', 'stock_check', 'comparison', 'cuotas_inquiry', 'shipping_inquiry'].includes(intent)) return 'interested';
  return 'browsing';
};

if (delivery.is_silent === true) {
  return [{
    json: {
      is_silent: true,
      payload: null,
      needs_human: false,
      clean_text: '',
      metadata: { intent: 'followup', funnel_update: 'no_change', products: 'none', city_detected: 'none', is_salta: 'unknown', brand_interest: 'none', budget_hint: 'none' },
      products_list: [],
      subscriber_id: mergedData.subscriber_id,
      user_message: mergedData.user_message,
      was_audio: mergedData.was_audio,
      customer_id: contextData.customer_id,
      current_funnel_stage: contextData.customer_profile?.funnel_stage || null
    }
  }];
}

let cleanText = sanitizeInternalIds(delivery.reply_text || 'Disculpá, ¿me repetís la consulta?');

const MAX_CHARS = 1600;
const MAX_MESSAGES = 8;

const splitTextSafely = (text, maxChars = MAX_CHARS, maxMessages = MAX_MESSAGES) => {
  const normalized = String(text || '').replace(/\r/g, '').trim();
  if (!normalized) return [];

  const sentenceParts = normalized
    .split(/\n+/)
    .flatMap((part) => part.split(/(?<=[.!?])\s+/))
    .map((p) => p.trim())
    .filter(Boolean);

  const chunks = [];
  let current = '';

  const pushCurrent = () => {
    if (current && current.trim()) chunks.push(current.trim());
    current = '';
  };

  const appendPiece = (piece) => {
    if (!piece) return;
    if (!current) {
      current = piece;
      return;
    }
    if ((current.length + 1 + piece.length) <= maxChars) {
      current += ' ' + piece;
    } else {
      pushCurrent();
      current = piece;
    }
  };

  for (const part of sentenceParts) {
    if (part.length <= maxChars) {
      appendPiece(part);
      continue;
    }

    const words = part.split(/\s+/).filter(Boolean);
    let local = '';

    const pushLocal = () => {
      if (local) appendPiece(local.trim());
      local = '';
    };

    for (const word of words) {
      if (word.length > maxChars) {
        pushLocal();
        for (let i = 0; i < word.length; i += maxChars) {
          appendPiece(word.slice(i, i + maxChars));
        }
        continue;
      }

      if (!local) {
        local = word;
      } else if ((local.length + 1 + word.length) <= maxChars) {
        local += ' ' + word;
      } else {
        pushLocal();
        local = word;
      }
    }

    pushLocal();
  }

  pushCurrent();

  if (chunks.length <= maxMessages) return chunks;

  const trimmed = chunks.slice(0, maxMessages);
  const note = '... Si querés, te lo paso más resumido por marca/modelo 👌';
  const last = trimmed[trimmed.length - 1] || '';
  const allowed = maxChars - note.length - 1;
  trimmed[trimmed.length - 1] = (allowed > 50 ? last.slice(0, allowed).trim() : last.slice(0, maxChars - 1).trim()) + '\n' + note;
  return trimmed;
};

const textChunks = splitTextSafely(cleanText, MAX_CHARS, MAX_MESSAGES);
const messagesArray = textChunks.length > 0
  ? textChunks.map((chunk) => ({ type: 'text', text: sanitizeInternalIds(chunk) }))
  : [{ type: 'text', text: 'Disculpá, ¿me repetís la consulta?' }];

const mediaMessages = Array.isArray(media.image_messages) ? media.image_messages : [];
if (orchestrator.wants_images && mediaMessages.length > 0) {
  for (const img of mediaMessages.slice(0, 4)) {
    if (img?.url && String(img.url).startsWith('http')) {
      messagesArray.push({ type: 'image', url: img.url, image_url: img.url });
    }
  }
}

const productsFromCatalog = Array.isArray(catalog.matched_product_keys) ? catalog.matched_product_keys : [];
const productsFromMedia = Array.isArray(media.products_for_metadata) ? media.products_for_metadata : [];
const productsList = [...new Set([...productsFromMedia, ...productsFromCatalog])].filter(Boolean).slice(0, 6);

const intent = mapIntent(orchestrator.intent_primary);
const needsHuman = orchestrator.needs_human === true;

const metadata = {
  intent,
  products: productsList.length > 0 ? productsList.join(', ') : 'none',
  funnel_update: mapFunnel(intent, needsHuman),
  city_detected: orchestrator.city_detected || 'none',
  is_salta: orchestrator.is_salta || 'unknown',
  brand_interest: catalog.brand_interest || orchestrator.brand_interest || 'none',
  budget_hint: orchestrator.budget_hint || 'none'
};

const payload = {
  subscriber_id: mergedData.subscriber_id,
  data: {
    version: 'v2',
    content: {
      type: 'whatsapp',
      messages: messagesArray
    }
  }
};

return [{
  json: {
    is_silent: false,
    payload,
    needs_human: needsHuman,
    clean_text: cleanText,
    metadata,
    products_list: productsList,
    subscriber_id: mergedData.subscriber_id,
    user_message: mergedData.user_message,
    was_audio: mergedData.was_audio,
    customer_id: contextData.customer_id,
    current_funnel_stage: contextData.customer_profile?.funnel_stage || null
  }
}];

const data = $('Process Response').first().json;
const metadata = data.metadata || {};
const products = Array.isArray(data.products_list) ? data.products_list : [];

return [{
  json: {
    manychat_id: data.subscriber_id,
    customer_id: data.customer_id || null,
    role: 'bot',
    message: data.clean_text || '(solo imágenes)',
    message_type: 'text',
    intent_detected: metadata.intent || null,
    products_mentioned: products,
    triggered_human: data.needs_human || false,
    was_audio: false
  }
}];

const data = $('Process Response').first().json;
const metadata = data.metadata || {};
const products = Array.isArray(data.products_list) ? data.products_list : [];

const stageRank = {
  new: 0,
  browsing: 1,
  interested: 2,
  closing: 3,
  human_handoff: 4
};

const currentStage = String(data.current_funnel_stage || '').trim().toLowerCase();
const requestedStage = String(metadata.funnel_update || '').trim().toLowerCase();

const updates = {
  last_bot_interaction: new Date().toISOString(),
  updated_at: new Date().toISOString()
};

if (requestedStage && requestedStage !== 'no_change') {
  if (stageRank[requestedStage] !== undefined) {
    if (stageRank[currentStage] === undefined || stageRank[requestedStage] >= stageRank[currentStage]) {
      updates.funnel_stage = requestedStage;
    }
  }
}

if (metadata.city_detected && metadata.city_detected !== 'none') {
  let city = metadata.city_detected.trim();
  const lower = city.toLowerCase();
  if (['salta', 'salta capital', 'salta cap'].includes(lower)) {
    city = 'Salta Capital';
    updates.is_salta_capital = true;
  }
  updates.city = city;
}

if (metadata.is_salta === 'true') updates.is_salta_capital = true;
else if (metadata.is_salta === 'false') updates.is_salta_capital = false;

if (metadata.brand_interest && metadata.brand_interest !== 'none') updates.preferred_brand = metadata.brand_interest;
if (metadata.budget_hint && metadata.budget_hint !== 'none') updates.preferred_budget = metadata.budget_hint;
if (products.length > 0) updates.interested_product = products[0];

if (data.needs_human) {
  updates.human_assigned = true;
  updates.funnel_stage = 'human_handoff';
}

return [{ json: { subscriber_id: data.subscriber_id, updates } }];

// Backfill intent on the user's saved message after AI classification
const data = $('Process Response').first().json;
const metadata = data.metadata || {};

const saveNode = $('Save Incoming Message').first();
let savedId = null;
const savedBody = saveNode.json;
if (Array.isArray(savedBody) && savedBody.length > 0) {
  savedId = savedBody[0]?.id;
} else if (savedBody && savedBody.id) {
  savedId = savedBody.id;
}

const intent = String(metadata.intent || '').trim();
if (!savedId || !intent) {
  return [];
}

return [{
  json: {
    message_id: savedId,
    intent
  }
}];

// Link the incoming conversation row to the upserted customer_id (best effort)
const upsertRaw = $input.first().json;

const toIntOrNull = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
};

const extractCustomerId = (raw) => {
  if (typeof raw === 'number' && Number.isFinite(raw)) return raw;
  if (typeof raw === 'string') return toIntOrNull(raw);

  if (Array.isArray(raw) && raw.length > 0) {
    const first = raw[0];
    if (typeof first === 'number' && Number.isFinite(first)) return first;
    if (typeof first === 'string') return toIntOrNull(first);
    if (first && typeof first === 'object') {
      if (first.upsert_customer !== undefined && first.upsert_customer !== null) return toIntOrNull(first.upsert_customer);
      if (first.customer_id !== undefined && first.customer_id !== null) return toIntOrNull(first.customer_id);
      if (first.id !== undefined && first.id !== null) return toIntOrNull(first.id);
    }
  }

  if (raw && typeof raw === 'object') {
    if (raw.upsert_customer !== undefined && raw.upsert_customer !== null) return toIntOrNull(raw.upsert_customer);
    if (raw.customer_id !== undefined && raw.customer_id !== null) return toIntOrNull(raw.customer_id);
    if (raw.id !== undefined && raw.id !== null) return toIntOrNull(raw.id);
  }

  return null;
};

const customerId = extractCustomerId(upsertRaw);

const saveNode = $('Save Incoming Message').first();
const savedBody = saveNode.json;
let messageId = null;
if (Array.isArray(savedBody) && savedBody.length > 0) {
  messageId = savedBody[0]?.id;
} else if (savedBody && savedBody.id) {
  messageId = savedBody.id;
}

const parsedMessageId = toIntOrNull(messageId);
if (!Number.isFinite(customerId) || !Number.isFinite(parsedMessageId)) {
  return [];
}

return [{
  json: {
    message_id: parsedMessageId,
    customer_id: customerId
  }
}];

// Agent 1 - Orchestrator
// Strict contract: classifies intent and routing flags only.

const ctx = $input.first().json;

const normalize = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const textRaw = String(ctx.user_message || '').trim();
const text = normalize(textRaw);
const isEmpty = text.length === 0;

const has = (re) => re.test(text);

const flags = {
  wants_images: has(/\b(foto|fotos|imagen|imagenes|mandame|enviame|mostrame|mostrar foto|quiero ver)\b/),
  wants_catalog: has(/\b(catalogo|catologo|lista|todos|todo el catalogo|ver todo|android y iphone|iphone y android|que tienen|precios)\b/),
  wants_payment: has(/\b(pago|pagos|transferencia|tarjeta|credito|debito|btc|bitcoin|usdt|trc|cripto|crypto|efectivo|dolares|dólares)\b/),
  wants_shipping: has(/\b(envio|envios|despacho|sucursal|oca|buspack|via cargo|flecha|entrega|retiro|shipping)\b/),
  wants_installments: has(/\b(cuotas|cuota|financiacion|financiación|6 cuotas|6cts|bancarizada|macro)\b/),
  wants_human: has(/\b(humano|persona|asesor|agente|joaco|joaquin|joaquín)\b/),
  complaint: has(/\b(reclamo|queja|devolucion|devolución|garantia|garantía|problema|estafa|denuncia)\b/),
  post_sale: has(/\b(ya pague|ya pagué|mi pedido|seguimiento|tracking|cuando llega|cu[aá]ndo llega|ya transferi|ya transferí)\b/),
  greeting: has(/^(hola|buenas|buen dia|buenos dias|buenas tardes|buenas noches|que tal|q tal)$/),
  comparison: has(/\b(vs|comparar|comparacion|comparación|diferencia|cual conviene|cu[aá]l conviene|entre)\b/)
};

const brandInterest = (() => {
  if (has(/\b(iphone|apple)\b/)) return 'IPHONE';
  if (has(/\b(samsung|galaxy)\b/)) return 'SAMSUNG';
  if (has(/\b(redmi|poco|xiaomi)\b/)) return 'REDMI/POCO';
  return 'none';
})();

let intent = 'followup';
if (isEmpty) intent = 'followup';
else if (flags.wants_human || flags.complaint || flags.post_sale) intent = 'complaint';
else if (flags.wants_installments) intent = 'cuotas_inquiry';
else if (flags.wants_shipping) intent = 'shipping_inquiry';
else if (flags.wants_payment) intent = 'price_inquiry';
else if (flags.comparison) intent = 'comparison';
else if (flags.wants_catalog) intent = 'price_inquiry';
else if (flags.greeting) intent = 'greeting';

const needsHuman = flags.wants_human || flags.complaint || flags.post_sale;
const shouldReply = !isEmpty || Boolean(ctx.is_first_interaction);

return [{
  json: {
    ...ctx,
    agent_orchestrator: {
      version: '1.0',
      should_reply: shouldReply,
      intent_primary: intent,
      needs_human: needsHuman,
      wants_images: flags.wants_images,
      wants_catalog: flags.wants_catalog,
      wants_payment: flags.wants_payment,
      wants_shipping: flags.wants_shipping,
      wants_installments: flags.wants_installments,
      comparison: flags.comparison,
      brand_interest: brandInterest,
      budget_hint: /\b(barato|economico|económico|precio|budget)\b/.test(text) ? 'budget' : (/(premium|pro|max|ultra)/.test(text) ? 'premium' : 'none'),
      city_detected: /\bsalta\b/.test(text) ? 'salta' : 'none',
      is_salta: /\bsalta\b/.test(text) ? 'true' : 'unknown',
      flags,
      raw_text: textRaw
    }
  }
}];

// Agent 2 - Catalog & Pricing
// Strict contract: product matching and pricing blocks (no user-facing IDs).

const data = $input.first().json;
const o = data.agent_orchestrator || {};
const products = Array.isArray(data.product_catalog) ? data.product_catalog : [];

const normalize = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const text = normalize(o.raw_text || data.user_message || '');
const tokens = [...new Set(text.split(/\s+/).filter((w) => w.length >= 3 || /\d/.test(w)))];

const scoreProduct = (p) => {
  const name = normalize(p.product_name);
  const key = normalize(p.product_key);
  let score = 0;

  if (text && name.includes(text)) score += 12;
  if (text && key.includes(text)) score += 10;

  for (const t of tokens) {
    const weight = /\d/.test(t) ? 3 : 1;
    if (name.includes(t)) score += weight;
    if (key.includes(t)) score += weight;
  }

  if (o.brand_interest && o.brand_interest !== 'none' && p.brand === o.brand_interest) score += 2;
  if (p.in_stock === false) score -= 1;
  return score;
};

const matched = products
  .map((p) => ({ ...p, _score: scoreProduct(p) }))
  .filter((p) => p._score >= 4)
  .sort((a, b) => b._score - a._score)
  .slice(0, 8);

const formatPriceLine = (p) => {
  const ars = p.price_ars != null ? '$' + Number(p.price_ars).toLocaleString('es-AR') : 's/d';
  const usd = p.price_usd != null ? ' (USD ' + Number(p.price_usd) + ')' : '';
  const specs = [];
  if (p.ram_gb) specs.push(String(p.ram_gb) + 'GB RAM');
  if (p.storage_gb) specs.push(String(p.storage_gb) + 'GB');
  if (p.network) specs.push(String(p.network).toUpperCase());
  const specsStr = specs.length ? ' (' + specs.join(', ') + ')' : '';
  let line = p.product_name + specsStr + ' — ' + ars + usd;
  if (p.promo_price_ars) line += ' | promo $' + Number(p.promo_price_ars).toLocaleString('es-AR') + ' 💥';
  if (p.in_stock === false) line += ' [SIN STOCK]';
  return line;
};

const byBrand = {
  IPHONE: products.filter((p) => p.brand === 'IPHONE' && p.in_stock !== false).sort((a, b) => Number(b.price_ars || 0) - Number(a.price_ars || 0)),
  SAMSUNG: products.filter((p) => p.brand === 'SAMSUNG' && p.in_stock !== false).sort((a, b) => Number(b.price_ars || 0) - Number(a.price_ars || 0)),
  'REDMI/POCO': products.filter((p) => p.brand === 'REDMI/POCO' && p.in_stock !== false).sort((a, b) => Number(b.price_ars || 0) - Number(a.price_ars || 0))
};

const wantsFull = /\b(todos|todo el catalogo|catalogo completo|lista completa|android y iphone|iphone y android|todo)\b/.test(text);

let catalogMode = 'none';
let priorityReplyText = '';
let suggestedQuestion = null;

if (o.wants_catalog && !wantsFull && o.brand_interest === 'none') {
  catalogMode = 'ask_brand';
  priorityReplyText = 'Manejamos iPhone, Samsung y Redmi/POCO. ¿Cuál querés que te muestre primero?';
} else if (o.wants_catalog && wantsFull) {
  catalogMode = 'full_split';
  const block = (label, list) => {
    const lines = list.slice(0, 8).map(formatPriceLine);
    return label + ':\n' + lines.join('\n');
  };
  priorityReplyText = [
    'Dale, te paso un resumen por marca así queda claro 👇',
    block('iPhone', byBrand.IPHONE),
    block('Samsung', byBrand.SAMSUNG),
    block('Redmi/POCO', byBrand['REDMI/POCO']),
    'Si querés, después te paso el detalle completo de una marca puntual.'
  ].join('\n\n');
} else if (matched.length > 0) {
  catalogMode = 'matched';
  const lines = matched.slice(0, 4).map(formatPriceLine);
  priorityReplyText = lines.join('\n');
} else if (o.intent_primary === 'comparison' || o.wants_installments || o.wants_images) {
  catalogMode = 'need_clarification';
  suggestedQuestion = 'Decime el modelo exacto (por ejemplo A56 8+256 o A56 12+256) y te paso la info precisa.';
}

return [{
  json: {
    ...data,
    agent_catalog: {
      version: '1.0',
      catalog_mode: catalogMode,
      matched_product_keys: matched.map((p) => p.product_key),
      matched_products: matched.map((p) => ({
        product_key: p.product_key,
        product_name: p.product_name,
        brand: p.brand,
        price_ars: p.price_ars,
        promo_price_ars: p.promo_price_ars,
        price_usd: p.price_usd,
        in_stock: p.in_stock,
        image_url: p.image_url
      })),
      brand_interest: o.brand_interest || 'none',
      priority_reply_text: priorityReplyText,
      suggested_question: suggestedQuestion
    }
  }
}];

// Agent 3 - Policy
// Strict contract: canonical store policy answers.

const data = $input.first().json;
const o = data.agent_orchestrator || {};
const policy = data.store_policies || {};

const textBlocks = [];

if (o.needs_human) {
  textBlocks.push('Te ayudo con eso: te derivo con un asesor humano para resolverlo bien.');
}

if (o.wants_payment || o.wants_installments) {
  textBlocks.push('💳 Pagos: transferencia en pesos, transferencia en dólares, Bitcoin y USDT (TRC-20) 0% recargo, y efectivo (solo Salta Capital).');
  textBlocks.push('❌ No hacemos créditos personales.');
}

if (o.wants_shipping) {
  textBlocks.push('📦 Envíos GRATIS a sucursal (BusPack/Flecha Carga, OCA o Vía Cargo), sin costo de despacho ni embalaje.');
  textBlocks.push('🚚 El envío se realiza a partir de las 72 horas hábiles.');
  textBlocks.push('🔥 En Salta Capital coordinamos entrega presencial en el día. Interior de Salta: 24 hs.');
}

if (/\b(bitcoin|btc|usdt|trc)\b/i.test(String(o.raw_text || ''))) {
  textBlocks.push('Sí, aceptamos Bitcoin y USDT (TRC-20) con 0% recargo.');
}

if (/\b(donde|dónde|direccion|dirección|local|ubicacion|ubicación)\b/i.test(String(o.raw_text || ''))) {
  textBlocks.push('📍 ' + (policy.location || 'Caseros 1365, Salta Capital. Diagonal a OCA.'));
}

const policyOnly = (o.wants_payment || o.wants_shipping) && !(o.wants_catalog || o.wants_images);

return [{
  json: {
    ...data,
    agent_policy: {
      version: '1.0',
      policy_only: policyOnly,
      text_blocks: textBlocks,
      priority_reply_text: policyOnly ? textBlocks.join('\n') : ''
    }
  }
}];

// Agent 4 - Media
// Strict contract: image selection only when requested.

const data = $input.first().json;
const o = data.agent_orchestrator || {};
const c = data.agent_catalog || {};
const products = Array.isArray(data.product_catalog) ? data.product_catalog : [];

const imageMessages = [];
const textBlocks = [];
const productKeysForMetadata = [];

if (o.wants_images) {
  const matched = Array.isArray(c.matched_products) ? c.matched_products : [];

  let selected = matched.slice(0, 4);
  if (selected.length === 0) {
    const interest = String(data.customer_profile?.interested_product || '').toLowerCase();
    const byInterest = products.find((p) => String(p.product_name || '').toLowerCase().includes(interest) || String(p.product_key || '').toLowerCase().includes(interest));
    const fallback = products.filter((p) => p.image_url).slice(0, 4);
    selected = [byInterest, ...fallback].filter(Boolean).slice(0, 4);
  }

  const missing = [];
  const already = new Set();

  for (const p of selected) {
    if (!p || already.has(p.product_key)) continue;
    already.add(p.product_key);
    productKeysForMetadata.push(p.product_key);

    if (p.image_url && String(p.image_url).startsWith('http')) {
      imageMessages.push({ type: 'image', url: p.image_url, image_url: p.image_url });
    } else {
      missing.push(p.product_name || p.product_key);
    }
  }

  if (selected.length === 0) {
    const sample = products.filter((p) => p.image_url).slice(0, 4).map((p) => p.product_name);
    if (sample.length > 0) {
      textBlocks.push('📸 Tengo fotos de: ' + sample.join(', ') + '. Decime cuál querés y te la mando.');
    } else {
      textBlocks.push('⚠️ Por ahora no tengo fotos cargadas para enviarte, pero te paso precio y detalles si querés.');
    }
  }

  if (missing.length > 0) {
    textBlocks.push('⚠️ No tengo fotos de ' + missing.slice(0, 3).join(', ') + ' por el momento.');
  }
}

return [{
  json: {
    ...data,
    agent_media: {
      version: '1.0',
      wants_images: o.wants_images === true,
      image_messages: imageMessages,
      text_blocks: textBlocks,
      products_for_metadata: [...new Set(productKeysForMetadata)]
    }
  }
}];

// Agent 5 - Delivery
// Strict contract: compose final human text from previous agent contracts.

const data = $input.first().json;
const o = data.agent_orchestrator || {};
const c = data.agent_catalog || {};
const p = data.agent_policy || {};
const m = data.agent_media || {};

const compact = (s) => String(s || '').replace(/\s{2,}/g, ' ').trim();

if (o.should_reply === false) {
  return [{
    json: {
      ...data,
      agent_delivery: {
        version: '1.0',
        is_silent: true,
        reply_text: '',
        reason: 'empty_non_first_interaction'
      }
    }
  }];
}

if ((o.raw_text || '').trim() === '' && data.is_first_interaction) {
  return [{
    json: {
      ...data,
      agent_delivery: {
        version: '1.0',
        is_silent: false,
        reply_text: '😊 ¡Hola ' + (data.first_name || 'amigo') + '! ¿Cómo andás? Bienvenido a TechnoStore Salta 👋\nContame qué celular estás buscando y te ayudo al toque.'
      }
    }
  }];
}

const blocks = [];

if (c.priority_reply_text) blocks.push(c.priority_reply_text);
if (p.priority_reply_text && !c.priority_reply_text) blocks.push(p.priority_reply_text);

if (!c.priority_reply_text && !p.priority_reply_text) {
  if (Array.isArray(c.matched_products) && c.matched_products.length > 0) {
    blocks.push('Te paso opciones que tenemos ahora:');
    const lines = c.matched_products.slice(0, 3).map((x) => {
      const ars = x.price_ars != null ? '$' + Number(x.price_ars).toLocaleString('es-AR') : 's/d';
      const promo = x.promo_price_ars ? ', promo $' + Number(x.promo_price_ars).toLocaleString('es-AR') + ' 💥' : '';
      return '• ' + x.product_name + ': contado ' + ars + promo;
    });
    blocks.push(lines.join('\n'));
  } else if (o.intent_primary === 'greeting') {
    blocks.push('¡Hola ' + (data.first_name || 'amigo') + '! ¿Cómo andás? Decime qué modelo buscás y te paso precio al toque.');
  } else if (o.intent_primary === 'comparison') {
    blocks.push(c.suggested_question || 'Decime los dos modelos exactos y te hago la comparación clara de precio, specs y cuál conviene.');
  } else {
    blocks.push('Dale, contame el modelo exacto que buscás y te paso precio y stock al toque.');
  }
}

if (Array.isArray(p.text_blocks) && p.text_blocks.length > 0 && !p.policy_only) {
  for (const t of p.text_blocks.slice(0, 3)) {
    if (!blocks.includes(t)) blocks.push(t);
  }
}

if (Array.isArray(m.text_blocks) && m.text_blocks.length > 0) {
  for (const t of m.text_blocks.slice(0, 2)) {
    if (!blocks.includes(t)) blocks.push(t);
  }
}

let text = compact(blocks.join('\n\n'));
if (!text) text = 'Disculpá, ¿me repetís la consulta?';

if (!/cualquier cosa escribime/i.test(text)) {
  text += '\n\nCualquier cosa escribime 👋';
}

return [{
  json: {
    ...data,
    agent_delivery: {
      version: '1.0',
      is_silent: false,
      reply_text: text
    }
  }
}];
